import{_ as e,W as a,X as i,a0 as l}from"./framework-174e6972.js";const t={},r=l('<h2 id="_1-http的概念" tabindex="-1"><a class="header-anchor" href="#_1-http的概念" aria-hidden="true">#</a> 1. HTTP的概念</h2><p>超文本传输协议（Hypertext Transfer Protocol，HTTP）：定义了客户端和服务器端通信时，发送数据的格式。</p><figure><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaWeb/02.Servlet-HTTP-Request/202303271714737.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="_2-http的特点" tabindex="-1"><a class="header-anchor" href="#_2-http的特点" aria-hidden="true">#</a> 2. HTTP的特点</h2><ol><li>基于TCP/IP的高级协议，三次握手。</li><li>默认端口号:80</li><li>基于请求/响应模型的：发送一次请求对应一次响应</li><li>无状态的：每次请求之间相互独立，不能交互数据</li></ol><h2 id="_3-历史版本的区别" tabindex="-1"><a class="header-anchor" href="#_3-历史版本的区别" aria-hidden="true">#</a> 3. 历史版本的区别</h2><ul><li>1.0：每一次请求响应都会建立新的连接</li><li>1.1：复用连接</li></ul><blockquote><p>只用了解。</p></blockquote><h2 id="_4-请求消息-request-数据格式" tabindex="-1"><a class="header-anchor" href="#_4-请求消息-request-数据格式" aria-hidden="true">#</a> 4. 请求消息(Request)数据格式</h2><p>包含请求行、请求头(也叫请求头部)、请求空行、请求体（正文）。</p><figure><img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaWeb/02.Servlet-HTTP-Request/202303271715487.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="_4-1-请求行" tabindex="-1"><a class="header-anchor" href="#_4-1-请求行" aria-hidden="true">#</a> 4.1. 请求行</h3><p>这里的请求行的内容为<code>POST /demo HTTP/1.1</code>，请求行的格式为<code>请求方式 请求url 请求协议/版本</code>。</p><ul><li>请求方式： HTTP协议有7种请求方式，常用的有GET和POST 2种。 <ul><li>GET： <ol><li>请求参数放在请求行中，在url后。类似这种<code>http://localhost:8080/demo1?username=zhangsan</code>；</li><li>请求的url长度是有限制的；</li><li>不太安全，直接暴露在URL中。</li></ol></li><li>POST： <ol><li>请求参数在请求体中； <img src="https://hk-docs.oss-cn-chengdu.aliyuncs.com/java/JavaWeb/02.Servlet-HTTP-Request/202303271715706.jpg" alt="" loading="lazy"></li><li>请求的url长度没有限制；</li><li>相对安全，需要通过一定的操作才能看到。</li></ol></li></ul></li></ul><h3 id="_4-2-请求头" tabindex="-1"><a class="header-anchor" href="#_4-2-请求头" aria-hidden="true">#</a> 4.2. 请求头</h3><p>客户端浏览器告诉服务器一些信息。请求头的格式：<code>请求头名称: 请求头值</code>。</p><h3 id="_4-3-请求空行" tabindex="-1"><a class="header-anchor" href="#_4-3-请求空行" aria-hidden="true">#</a> 4.3. 请求空行</h3><p>空行，就是用于分割POST请求的请求头，和请求体的。</p><h3 id="_4-4-请求体-正文" tabindex="-1"><a class="header-anchor" href="#_4-4-请求体-正文" aria-hidden="true">#</a> 4.4. 请求体(正文)</h3><p>用来封装POST请求消息的请求参数。</p><h2 id="_5-响应消息-response-数据格式" tabindex="-1"><a class="header-anchor" href="#_5-响应消息-response-数据格式" aria-hidden="true">#</a> 5. 响应消息(response)数据格式</h2><blockquote><p>后续的进阶阶段学习。</p></blockquote>',22),h=[r];function d(o,c){return a(),i("div",null,h)}const n=e(t,[["render",d],["__file","5.HTTP-Request.html.vue"]]);export{n as default};
